    rs = l2_norm(r, n);
    if (rs < tol) {
        *iters = 0;
        *final_res = rs;
        return 0;
    }
    step_r(pack, r, z);
    memcpy(p, z, (size_t)n * sizeof(double));
    rz_old = 0.0;
    for (int i = 0; i < n; i++) {
        rz_old += r[i] * z[i];
    }
    for (k = 1; k <= max_iter; k++) {
        bsr_matvec(pack, p, ap);
        alpha = rz_old;
        double denom = 0.0;
        for (int i = 0; i < n; i++) {
