        alpha /= denom;
        for (int i = 0; i < n; i++) {
            x[i] += alpha * p[i];
            r[i] -= alpha * ap[i];
        }
        rs = l2_norm(r, n);
        if (rs < tol) {
            *iters = k;
            *final_res = rs;
            return 0;
        }
        step_r(pack, r, z);
        beta = 0.0;
        for (int i = 0; i < n; i++) {
            beta += r[i] * z[i];
        }
        beta /= rz_old;
        for (int i = 0; i < n; i++) {
            p[i] = z[i] + beta * p[i];
        }
        rz_old = 0.0;
        for (int i = 0; i < n; i++) {
            rz_old += r[i] * z[i];
        }
    }
